{
  "sentences": [
    {
      "text": "我覺得今天天氣很舒服。",
      "pinyin": "Wǒ juéde jīntiān tiānqì hěn shūfu.",
      "pinyin_numeric": "wo3 jue2de jin1tian1 tian1qi4 hen3 shu1fu.",
      "translation_en": "I think the weather today is very comfortable.",
      "translation_ko": "오늘 날씨가 아주 쾌적하다고 생각해요."
    },
    {
      "text": "你覺得這件衣服好看嗎？",
      "pinyin": "Nǐ juéde zhè jiàn yīfu hǎokàn ma?",
      "pinyin_numeric": "ni3 jue2de zhe4 jian4 yi1fu hao3kan4 ma0?",
      "translation_en": "Do you think this piece of clothing looks good?",
      "translation_ko": "이 옷이 예뻐 보인다고 생각하세요?"
    },
    {
      "text": "他覺得牛肉麵很好吃。",
      "pinyin": "Tā juéde niúròumiàn hěn hǎochī.",
      "pinyin_numeric": "ta1 jue2de niu2rou4mian4 hen3 hao3chi1.",
      "translation_en": "He thinks the beef noodle soup is very delicious.",
      "translation_ko": "그는 소고기 국수가 아주 맛있다고 생각해요."
    },
    {
      "text": "我覺得這家餐廳太貴了。",
      "pinyin": "Wǒ juéde zhè jiā cāntīng tài guì le.",
      "pinyin_numeric": "wo3 jue2de zhe4 jia1 can1ting1 tai4 gui4 le0.",
      "translation_en": "I think this restaurant is too expensive.",
      "translation_ko": "이 식당은 너무 비싸다고 생각해요."
    },
    {
      "text": "你覺得明天會下雨嗎？",
      "pinyin": "Nǐ juéde míngtiān huì xiàyǔ ma?",
      "pinyin_numeric": "ni3 jue2de ming2tian1 hui4 xia4yu3 ma0?",
      "translation_en": "Do you think it will rain tomorrow?",
      "translation_ko": "내일 비가 올 거라고 생각하세요?"
    },
    {
      "text": "她覺得這杯咖啡很香。",
      "pinyin": "Tā juéde zhè bēi kāfēi hěn xiāng.",
      "pinyin_numeric": "ta1 jue2de zhe4 bei1 ka1fei1 hen3 xiang1.",
      "translation_en": "She thinks this cup of coffee is very fragrant.",
      "translation_ko": "그녀는 이 커피가 아주 향기롭다고 생각해요."
    },
    {
      "text": "我覺得走路比坐車更健康。",
      "pinyin": "Wǒ juéde zǒulù bǐ zuò chē gèng jiànkāng.",
      "pinyin_numeric": "wo3 jue2de zou3lu4 bi3 zuo4 che1 geng4 jian4kang1.",
      "translation_en": "I think walking is healthier than taking a car.",
      "translation_ko": "걷는 것이 차를 타는 것보다 더 건강하다고 생각해요."
    },
    {
      "text": "你覺得這家店的服務好嗎？",
      "pinyin": "Nǐ juéde zhè jiā diàn de fúwù hǎo ma?",
      "pinyin_numeric": "ni3 jue2de zhe4 jia1 dian4 de0 fu2wu4 hao3 ma0?",
      "translation_en": "Do you think the service at this store is good?",
      "translation_ko": "이 가게의 서비스가 좋다고 생각하세요?"
    },
    {
      "text": "我覺得他今天心情不好。",
      "pinyin": "Wǒ juéde tā jīntiān xīnqíng bù hǎo.",
      "pinyin_numeric": "wo3 jue2de ta1 jin1tian1 xin1qing2 bu4 hao3.",
      "translation_en": "I think he is in a bad mood today.",
      "translation_ko": "그가 오늘 기분이 안 좋은 것 같아요."
    },
    {
      "text": "你覺得這條路很安全嗎？",
      "pinyin": "Nǐ juéde zhè tiáo lù hěn ānquán ma?",
      "pinyin_numeric": "ni3 jue2de zhe4 tiao2 lu4 hen3 an1quan2 ma0?",
      "translation_en": "Do you think this road is very safe?",
      "translation_ko": "이 길이 아주 안전하다고 생각하세요?"
    }
  ]
}
